// topic: telemetry/<nodeId>/<param>  payload: number
// or JSON payload {nodeId, values, ts}
let out;
if (typeof msg.payload === 'object' && msg.payload.nodeId) {
  out = msg.payload;
} else {
  const p = msg.topic.split('/');
  out = { nodeId: p[1], values: { [p[2]]: Number(msg.payload) }, ts: Date.now() };
}
msg.url = 'http://oneops-backend.data.svc.cluster.local/api/nodes/' + out.nodeId + '/readings';
msg.method = 'POST';
msg.headers = { 'content-type': 'application/json' };
msg.payload = { values: out.values, ts: out.ts };
return msg;

// The backend already persists readings; enable a node-red-node-mysql
// node here for an independent raw archive if desired.
return null;
